mapper.select:
select s.node_urn as tableNodeUrn, s.node_name as tableNodeName, n.node_name as columnNodeName, n.node_urn as columnNodeUrn from datafusion.asset_lineage_node n join (select node_urn, node_name from datafusion.asset_lineage_node where node_type = 'DATABASE' and node_sub_type = 'TABLE' and (string_to_array(node_urn, ':'))[2] = #{req.option.dataSourceName}
and nodeName like concat('%',#{req.option.nodeName},'%')
limit #{req.size} offset #{req.offset}) s on n.node_urn like concat(s.node_urn, ':%')

select id, node_urn, node_name, node_type, node_sub_type, node_prop, creator, updater, create_time, update_time
from asset_lineage_node
where node_urn = #{nodeUrn}
